public class Comparable2 {
    static class Student implements Comparable<Student> {
        String name; int gpa;
        Student(String n, int g) { name=n; gpa=g; }
        public int compareTo(Student o) { return Integer.compare(o.gpa, this.gpa); } // descending
        public String toString() { return name+"("+gpa+")"; }
    }
    public static void main(String[] args) {
        java.util.List<Student> list = new java.util.ArrayList<>();
        list.add(new Student("A",85)); list.add(new Student("B",92)); list.add(new Student("C",78));
        java.util.Collections.sort(list);
        list.forEach(System.out::println);
    }
}
